#!/usr/bin/env node
/**
 * Run Init-only import-closure validation multiple times (default **10**) to shake out
 * nondeterminism or flaky filesystem state locally. No-op for correctness — same as one run.
 *
 *   REPEATS=25 node scripts/repeat-init-only-validation.mjs
 */
import { spawnSync } from 'node:child_process';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkgRoot = path.resolve(__dirname, '..');
const repeats = Math.max(1, parseInt(process.env.REPEATS ?? '10', 10) || 10);

for (let i = 1; i <= repeats; i += 1) {
  const r = spawnSync(process.execPath, [path.join(__dirname, 'validate-init-only-import-closure.mjs')], {
    cwd: pkgRoot,
    stdio: i === repeats ? 'inherit' : 'pipe',
    encoding: 'utf8',
  });
  if (r.status !== 0) {
    console.error(`repeat-init-only-validation: failed on iteration ${i}/${repeats}`);
    process.exit(r.status ?? 1);
  }
  if (repeats > 1 && i < repeats) {
    console.log(`repeat-init-only-validation: OK ${i}/${repeats}`);
  }
}

if (repeats > 1) {
  console.log(`repeat-init-only-validation: ${repeats} passes OK`);
}
